@page "/apply"
@using sv_da3c4f5d1caf4facbe525aa58baa73be.Models
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<h1>Job Application</h1>

<!-- Step Indicator Bar -->
<nav class="step-indicator" aria-label="Application steps">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var stepIndex = i;
        var stepClass = GetStepClass(stepIndex);
        <button class="step-item @stepClass"
                disabled="@(!IsStepClickable(stepIndex))"
                @onclick="() => GoToStep(stepIndex)">
            <span class="step-circle">
                @if (IsStepCompleted(stepIndex))
                {
                    <span class="checkmark">&#10003;</span>
                }
                else
                {
                    @(stepIndex + 1)
                }
            </span>
            <span class="step-label">@StepNames[stepIndex]</span>
        </button>
    }
</nav>

<!-- Step Content -->
<div class="step-content">
    @if (!string.IsNullOrEmpty(_errorMessage))
    {
        <div class="alert alert-danger">@_errorMessage</div>
    }

    @switch (_currentStep)
    {
        case 0:
            @RenderPersonalInfo()
            break;
        case 1:
            @RenderWorkHistory()
            break;
        case 2:
            @RenderReferences()
            break;
        case 3:
            @RenderCoverLetter()
            break;
        case 4:
            @RenderReviewSubmit()
            break;
    }
</div>

@* Step 1: Personal Info *@
@{ RenderFragment RenderPersonalInfo() =>
    @<div class="form-step">
        <h2>Personal Information</h2>
        <div class="form-group">
            <label for="fullName">Full Name *</label>
            <input id="fullName" type="text" class="form-control" @bind="_fullName" />
        </div>
        <div class="form-group">
            <label for="email">Email *</label>
            <input id="email" type="email" class="form-control" @bind="_email" />
        </div>
        <div class="form-group">
            <label for="phone">Phone *</label>
            <input id="phone" type="tel" class="form-control" @bind="_phone" />
        </div>
        <div class="form-group">
            <label for="address">Address *</label>
            <input id="address" type="text" class="form-control" @bind="_address" />
        </div>
        <div class="form-actions">
            <button class="btn btn-primary" @onclick="NextFromPersonalInfo" disabled="@_isValidating">
                @if (_isValidating) { <span>Validating...</span> } else { <span>Next</span> }
            </button>
        </div>
    </div>;
}

@* Step 2: Work History *@
@{ RenderFragment RenderWorkHistory() =>
    @<div class="form-step">
        <h2>Work History</h2>
        @for (int i = 0; i < _workEntries.Count; i++)
        {
            var index = i;
            <div class="work-entry-card">
                <div class="work-entry-header">
                    <h3>Position @(index + 1)</h3>
                    @if (_workEntries.Count > 1)
                    {
                        <button class="btn btn-danger btn-sm" @onclick="() => RemoveWorkEntry(index)">Remove</button>
                    }
                </div>
                <div class="form-group">
                    <label>Company Name *</label>
                    <input type="text" class="form-control" @bind="_workEntries[index].Company" />
                </div>
                <div class="form-group">
                    <label>Job Title *</label>
                    <input type="text" class="form-control" @bind="_workEntries[index].Title" />
                </div>
                <div class="form-row">
                    <div class="form-group">
                        <label>Start Date *</label>
                        <input type="date" class="form-control" @bind="_workEntries[index].StartDate" />
                    </div>
                    <div class="form-group">
                        <label>End Date</label>
                        <input type="date" class="form-control" @bind="_workEntries[index].EndDate"
                               disabled="@_workEntries[index].IsCurrent" />
                    </div>
                </div>
                <div class="form-group form-check">
                    <input type="checkbox" class="form-check-input" id="current-@index"
                           @bind="_workEntries[index].IsCurrent" />
                    <label class="form-check-label" for="current-@index">I currently work here</label>
                </div>
                <div class="form-group">
                    <label>Description *</label>
                    <textarea class="form-control" rows="3" @bind="_workEntries[index].Description"></textarea>
                </div>
            </div>
        }
        <button class="btn btn-secondary" @onclick="AddWorkEntry">+ Add Another Position</button>
        <div class="form-actions">
            <button class="btn btn-outline" @onclick="PreviousStep">Back</button>
            <button class="btn btn-primary" @onclick="NextFromWorkHistory">Next</button>
        </div>
    </div>;
}

@* Step 3: References *@
@{ RenderFragment RenderReferences() =>
    @<div class="form-step">
        <h2>References</h2>
        @for (int i = 0; i < _references.Count; i++)
        {
            var index = i;
            <div class="reference-card">
                <div class="work-entry-header">
                    <h3>Reference @(index + 1)</h3>
                    @if (_references.Count > 2)
                    {
                        <button class="btn btn-danger btn-sm" @onclick="() => RemoveReference(index)">Remove</button>
                    }
                </div>
                <div class="form-group">
                    <label>Name *</label>
                    <input type="text" class="form-control" @bind="_references[index].Name" />
                </div>
                <div class="form-group">
                    <label>Relationship *</label>
                    <input type="text" class="form-control" @bind="_references[index].Relationship" />
                </div>
                <div class="form-group">
                    <label>Email *</label>
                    <input type="email" class="form-control" @bind="_references[index].Email" />
                </div>
                <div class="form-group">
                    <label>Phone *</label>
                    <input type="tel" class="form-control" @bind="_references[index].Phone" />
                </div>
            </div>
        }
        @if (_references.Count < 3)
        {
            <button class="btn btn-secondary" @onclick="AddReference">+ Add Reference</button>
        }
        <div class="form-actions">
            <button class="btn btn-outline" @onclick="PreviousStep">Back</button>
            <button class="btn btn-primary" @onclick="NextFromReferences">Next</button>
        </div>
    </div>;
}

@* Step 4: Cover Letter *@
@{ RenderFragment RenderCoverLetter() =>
    @<div class="form-step">
        <h2>Cover Letter</h2>
        <div class="form-group">
            <label for="coverLetter">Write your cover letter</label>
            <textarea id="coverLetter" class="form-control cover-letter-input" rows="12"
                      @bind="_coverLetter" @bind:event="oninput" maxlength="2000"></textarea>
            <div class="character-count">@_coverLetter.Length / 2000 characters</div>
        </div>
        <div class="form-actions">
            <button class="btn btn-outline" @onclick="PreviousStep">Back</button>
            <button class="btn btn-primary" @onclick="NextFromCoverLetter">Next</button>
        </div>
    </div>;
}

@* Step 5: Review & Submit *@
@{ RenderFragment RenderReviewSubmit() =>
    @<div class="form-step">
        <h2>Review & Submit</h2>

        @if (_isSubmitted)
        {
            <div class="confirmation">
                <h3>&#10003; Application Submitted Successfully!</h3>
                <p>Your application ID is: <strong>@_applicationId</strong></p>
                <p>Thank you for applying. We will review your application and get back to you.</p>
            </div>
        }
        else
        {
            <div class="review-section">
                <div class="review-header">
                    <h3>Personal Information</h3>
                    <button class="btn-link" @onclick="() => GoToStep(0)">Edit</button>
                </div>
                <dl>
                    <dt>Full Name</dt><dd>@_fullName</dd>
                    <dt>Email</dt><dd>@_email</dd>
                    <dt>Phone</dt><dd>@_phone</dd>
                    <dt>Address</dt><dd>@_address</dd>
                </dl>
            </div>

            <div class="review-section">
                <div class="review-header">
                    <h3>Work History</h3>
                    <button class="btn-link" @onclick="() => GoToStep(1)">Edit</button>
                </div>
                @foreach (var entry in _workEntries)
                {
                    <div class="review-entry">
                        <strong>@entry.Title</strong> at <strong>@entry.Company</strong><br />
                        <span>@entry.StartDate.ToString("MMM yyyy") — @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))</span><br />
                        <p>@entry.Description</p>
                    </div>
                }
            </div>

            <div class="review-section">
                <div class="review-header">
                    <h3>References</h3>
                    <button class="btn-link" @onclick="() => GoToStep(2)">Edit</button>
                </div>
                @foreach (var reference in _references)
                {
                    <div class="review-entry">
                        <strong>@reference.Name</strong> (@reference.Relationship)<br />
                        <span>@reference.Email | @reference.Phone</span>
                    </div>
                }
            </div>

            <div class="review-section">
                <div class="review-header">
                    <h3>Cover Letter</h3>
                    <button class="btn-link" @onclick="() => GoToStep(3)">Edit</button>
                </div>
                <p class="cover-letter-preview">@_coverLetter</p>
            </div>

            <div class="form-actions">
                <button class="btn btn-outline" @onclick="PreviousStep">Back</button>
                <button class="btn btn-success btn-lg" @onclick="SubmitApplication" disabled="@_isSubmitting">
                    @if (_isSubmitting) { <span>Submitting...</span> } else { <span>Submit Application</span> }
                </button>
            </div>
        }
    </div>;
}

@code {
    private static readonly string[] StepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    private int _currentStep;
    private readonly HashSet<int> _completedSteps = new();
    private string _errorMessage = string.Empty;
    private bool _isValidating;
    private bool _isSubmitting;
    private bool _isSubmitted;
    private int _applicationId;

    // Step 1: Personal Info
    private string _fullName = string.Empty;
    private string _email = string.Empty;
    private string _phone = string.Empty;
    private string _address = string.Empty;

    // Step 2: Work History
    private List<WorkEntryModel> _workEntries = new() { new WorkEntryModel() };

    // Step 3: References
    private List<ReferenceModel> _references = new() { new ReferenceModel(), new ReferenceModel() };

    // Step 4: Cover Letter
    private string _coverLetter = string.Empty;

    private string GetStepClass(int step)
    {
        if (step == _currentStep) return "active";
        if (_completedSteps.Contains(step)) return "completed";
        return "dimmed";
    }

    private bool IsStepCompleted(int step) => _completedSteps.Contains(step);

    private bool IsStepClickable(int step) => _completedSteps.Contains(step) && step != _currentStep;

    private void GoToStep(int step)
    {
        if (_completedSteps.Contains(step) || step == _currentStep)
        {
            _errorMessage = string.Empty;
            _currentStep = step;
        }
    }

    private async Task NextFromPersonalInfo()
    {
        _errorMessage = string.Empty;

        if (string.IsNullOrWhiteSpace(_fullName) || string.IsNullOrWhiteSpace(_email) ||
            string.IsNullOrWhiteSpace(_phone) || string.IsNullOrWhiteSpace(_address))
        {
            _errorMessage = "All fields are required.";
            return;
        }

        _isValidating = true;
        try
        {
            var isValid = await ApplicationService.ValidateEmailAsync(_email);
            if (!isValid)
            {
                _errorMessage = "The email address is not valid.";
                return;
            }

            _completedSteps.Add(0);
            _currentStep = 1;
        }
        finally
        {
            _isValidating = false;
        }
    }

    private void NextFromWorkHistory()
    {
        _errorMessage = string.Empty;

        foreach (var entry in _workEntries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title) ||
