            <button class="btn btn-primary" @onclick="NextFromCoverLetter">Next</button>
        </div>
    </div>;
}

@* Step 5: Review & Submit *@
@{ RenderFragment RenderReviewSubmit() =>
    @<div class="form-step">
        <h2>Review & Submit</h2>

        @if (_isSubmitted)
        {
            <div class="confirmation">
                <h3>&#10003; Application Submitted Successfully!</h3>
                <p>Your application ID is: <strong>@_applicationId</strong></p>
                <p>Thank you for applying. We will review your application and get back to you.</p>
            </div>
        }
        else
        {
            <div class="review-section">
                <div class="review-header">
                    <h3>Personal Information</h3>
                    <button class="btn-link" @onclick="() => GoToStep(0)">Edit</button>
                </div>
                <dl>
                    <dt>Full Name</dt><dd>@_fullName</dd>
                    <dt>Email</dt><dd>@_email</dd>
                    <dt>Phone</dt><dd>@_phone</dd>
                    <dt>Address</dt><dd>@_address</dd>
                </dl>
            </div>

            <div class="review-section">
                <div class="review-header">
                    <h3>Work History</h3>
                    <button class="btn-link" @onclick="() => GoToStep(1)">Edit</button>
                </div>
                @foreach (var entry in _workEntries)
                {
                    <div class="review-entry">
                        <strong>@entry.Title</strong> at <strong>@entry.Company</strong><br />
                        <span>@entry.StartDate.ToString("MMM yyyy") — @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))</span><br />
                        <p>@entry.Description</p>
                    </div>
                }
            </div>

            <div class="review-section">
                <div class="review-header">
                    <h3>References</h3>
                    <button class="btn-link" @onclick="() => GoToStep(2)">Edit</button>
                </div>
                @foreach (var reference in _references)
                {
                    <div class="review-entry">
                        <strong>@reference.Name</strong> (@reference.Relationship)<br />
                        <span>@reference.Email | @reference.Phone</span>
                    </div>
                }
            </div>

