                <div class="review-header">
                    <h3>Cover Letter</h3>
                    <button class="btn-link" @onclick="() => GoToStep(3)">Edit</button>
                </div>
                <p class="cover-letter-preview">@_coverLetter</p>
            </div>

            <div class="form-actions">
                <button class="btn btn-outline" @onclick="PreviousStep">Back</button>
                <button class="btn btn-success btn-lg" @onclick="SubmitApplication" disabled="@_isSubmitting">
                    @if (_isSubmitting) { <span>Submitting...</span> } else { <span>Submit Application</span> }
                </button>
            </div>
        }
    </div>;
}

@code {
    private static readonly string[] StepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    private int _currentStep;
    private readonly HashSet<int> _completedSteps = new();
    private string _errorMessage = string.Empty;
    private bool _isValidating;
    private bool _isSubmitting;
    private bool _isSubmitted;
    private int _applicationId;

    // Step 1: Personal Info
    private string _fullName = string.Empty;
    private string _email = string.Empty;
    private string _phone = string.Empty;
    private string _address = string.Empty;

    // Step 2: Work History
    private List<WorkEntryModel> _workEntries = new() { new WorkEntryModel() };

    // Step 3: References
    private List<ReferenceModel> _references = new() { new ReferenceModel(), new ReferenceModel() };

    // Step 4: Cover Letter
    private string _coverLetter = string.Empty;

    private string GetStepClass(int step)
    {
        if (step == _currentStep) return "active";
        if (_completedSteps.Contains(step)) return "completed";
        return "dimmed";
    }

    private bool IsStepCompleted(int step) => _completedSteps.Contains(step);

    private bool IsStepClickable(int step) => _completedSteps.Contains(step) && step != _currentStep;

    private void GoToStep(int step)
    {
        if (_completedSteps.Contains(step) || step == _currentStep)
        {
            _errorMessage = string.Empty;
            _currentStep = step;
        }
    }

    private async Task NextFromPersonalInfo()
    {
        _errorMessage = string.Empty;

        if (string.IsNullOrWhiteSpace(_fullName) || string.IsNullOrWhiteSpace(_email) ||
            string.IsNullOrWhiteSpace(_phone) || string.IsNullOrWhiteSpace(_address))
        {
            _errorMessage = "All fields are required.";
            return;
        }

        _isValidating = true;
        try
        {
            var isValid = await ApplicationService.ValidateEmailAsync(_email);
            if (!isValid)
            {
                _errorMessage = "The email address is not valid.";
                return;
            }

            _completedSteps.Add(0);
            _currentStep = 1;
        }
        finally
        {
            _isValidating = false;
        }
    }

    private void NextFromWorkHistory()
    {
        _errorMessage = string.Empty;

        foreach (var entry in _workEntries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title) ||
                entry.StartDate == default || string.IsNullOrWhiteSpace(entry.Description))
            {
                _errorMessage = "Please fill in all required fields for each work entry.";
                return;
            }
        }

        _completedSteps.Add(1);
        _currentStep = 2;
    }

    private void NextFromReferences()
    {
        _errorMessage = string.Empty;

        foreach (var reference in _references)
        {
            if (string.IsNullOrWhiteSpace(reference.Name) || string.IsNullOrWhiteSpace(reference.Relationship) ||
                string.IsNullOrWhiteSpace(reference.Email) || string.IsNullOrWhiteSpace(reference.Phone))
            {
                _errorMessage = "Please fill in all required fields for each reference.";
                return;
            }
        }

        _completedSteps.Add(2);
        _currentStep = 3;
    }

    private void NextFromCoverLetter()
    {
        _errorMessage = string.Empty;

        if (string.IsNullOrWhiteSpace(_coverLetter))
        {
            _errorMessage = "Please write a cover letter.";
            return;
        }

        _completedSteps.Add(3);
        _currentStep = 4;
    }

    private void PreviousStep()
    {
        _errorMessage = string.Empty;
        if (_currentStep > 0)
            _currentStep--;
    }

    private void AddWorkEntry() => _workEntries.Add(new WorkEntryModel());

    private void RemoveWorkEntry(int index)
    {
        if (_workEntries.Count > 1)
            _workEntries.RemoveAt(index);
    }

    private void AddReference()
    {
        if (_references.Count < 3)
            _references.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (_references.Count > 2)
            _references.RemoveAt(index);
    }

    private async Task SubmitApplication()
    {
        _isSubmitting = true;
        _errorMessage = string.Empty;

        try
        {
            var personal = new PersonalInfo(_fullName, _email, _phone, _address);

            var workEntries = _workEntries.Select(e =>
                new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description)).ToList();
            var work = new WorkHistory(workEntries);

            var references = _references.Select(r =>
                new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();

            var application = new JobApplication(personal, work, references, _coverLetter);

            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _completedSteps.Add(4);
            _isSubmitted = true;
        }
        catch (Exception ex)
        {
            _errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _isSubmitting = false;
        }
    }

    private class WorkEntryModel
    {
