@page "/apply"
@using sv_da3c4f5d1caf4facbe525aa58baa73be.Models
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<h1>Job Application</h1>

<!-- Step Indicator Bar -->
<nav class="step-indicator" aria-label="Application steps">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var stepIndex = i;
        var stepClass = GetStepClass(stepIndex);
        <button class="step-item @stepClass"
                disabled="@(!IsStepClickable(stepIndex))"
                @onclick="() => GoToStep(stepIndex)">
            <span class="step-circle">
                @if (IsStepCompleted(stepIndex))
                {
                    <span class="checkmark">&#10003;</span>
                }
                else
                {
                    @(stepIndex + 1)
                }
            </span>
            <span class="step-label">@StepNames[stepIndex]</span>
        </button>
    }
</nav>

<!-- Step Content -->
<div class="step-content">
    @if (!string.IsNullOrEmpty(_errorMessage))
    {
        <div class="alert alert-danger">@_errorMessage</div>
    }

    @switch (_currentStep)
    {
        case 0:
            @RenderPersonalInfo()
            break;
        case 1:
            @RenderWorkHistory()
            break;
        case 2:
            @RenderReferences()
            break;
        case 3:
            @RenderCoverLetter()
            break;
        case 4:
            @RenderReviewSubmit()
            break;
    }
</div>

@* Step 1: Personal Info *@
@{ RenderFragment RenderPersonalInfo() =>
    @<div class="form-step">
        <h2>Personal Information</h2>
        <div class="form-group">
            <label for="fullName">Full Name *</label>
            <input id="fullName" type="text" class="form-control" @bind="_fullName" />
        </div>
        <div class="form-group">
            <label for="email">Email *</label>
            <input id="email" type="email" class="form-control" @bind="_email" />
        </div>
        <div class="form-group">
            <label for="phone">Phone *</label>
            <input id="phone" type="tel" class="form-control" @bind="_phone" />
        </div>
        <div class="form-group">
            <label for="address">Address *</label>
            <input id="address" type="text" class="form-control" @bind="_address" />
        </div>
        <div class="form-actions">
            <button class="btn btn-primary" @onclick="NextFromPersonalInfo" disabled="@_isValidating">
                @if (_isValidating) { <span>Validating...</span> } else { <span>Next</span> }
            </button>
        </div>
    </div>;
}

@* Step 2: Work History *@
@{ RenderFragment RenderWorkHistory() =>
    @<div class="form-step">
        <h2>Work History</h2>
        @for (int i = 0; i < _workEntries.Count; i++)
        {
            var index = i;
