                <div class="work-entry-header">
                    <h3>Position @(index + 1)</h3>
                    @if (_workEntries.Count > 1)
                    {
                        <button class="btn btn-danger btn-sm" @onclick="() => RemoveWorkEntry(index)">Remove</button>
                    }
                </div>
                <div class="form-group">
                    <label>Company Name *</label>
                    <input type="text" class="form-control" @bind="_workEntries[index].Company" />
                </div>
                <div class="form-group">
                    <label>Job Title *</label>
                    <input type="text" class="form-control" @bind="_workEntries[index].Title" />
                </div>
                <div class="form-row">
                    <div class="form-group">
                        <label>Start Date *</label>
                        <input type="date" class="form-control" @bind="_workEntries[index].StartDate" />
                    </div>
                    <div class="form-group">
                        <label>End Date</label>
                        <input type="date" class="form-control" @bind="_workEntries[index].EndDate"
                               disabled="@_workEntries[index].IsCurrent" />
                    </div>
                </div>
                <div class="form-group form-check">
                    <input type="checkbox" class="form-check-input" id="current-@index"
                           @bind="_workEntries[index].IsCurrent" />
                    <label class="form-check-label" for="current-@index">I currently work here</label>
                </div>
                <div class="form-group">
                    <label>Description *</label>
                    <textarea class="form-control" rows="3" @bind="_workEntries[index].Description"></textarea>
                </div>
            </div>
        }
        <button class="btn btn-secondary" @onclick="AddWorkEntry">+ Add Another Position</button>
        <div class="form-actions">
            <button class="btn btn-outline" @onclick="PreviousStep">Back</button>
            <button class="btn btn-primary" @onclick="NextFromWorkHistory">Next</button>
        </div>
    </div>;
